export type Cell = [x: number, y: number];

const key = (x: number, y: number): string => `${x},${y}`;

export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const live = new Set(liveCells.map(([x, y]) => key(x, y)));
  const neighborCounts = new Map<string, number>();

  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const k = key(x + dx, y + dy);
        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
      }
    }
  }

  const next: Cell[] = [];
  for (const [k, count] of neighborCounts) {
    const [xs, ys] = k.split(",");
    const x = Number(xs);
    const y = Number(ys);
    const isLive = live.has(k);
    if (isLive && (count === 2 || count === 3)) next.push([x, y]);
    else if (!isLive && count === 3) next.push([x, y]);
  }
  return next;
};

